import django.contrib.auth as auth
from saml2 import SamlBase, SamlElement, SamlXpath

class SamlServiceProvider(object):
    def handle_post_response(self, request):
        try:
            saml = SamlBase(request)
            name_id = SamlXpath(saml.find('./assertion/subject/name_id')).text
            attributes = SamlXpath(saml.find('.//assertion/attribute')).text

            user = auth.get_user(name=name_id)
            if not user:
                user = auth.create_user(name=name_id)

            for attribute in attributes:
                user.set_password(attribute)
                user.save()

            return user
        except Exception as e:
            raise ValueError("Failed to parse SAML POST response") from e